#include <capstone/capstone.h>

std::vector<DisassemblyResult> RealDisassemble(const uint8_t* code, size_t size) {
    csh handle;
    cs_open(CS_ARCH_X86, CS_MODE_64, &handle);
    cs_option(handle, CS_OPT_SYNTAX, CS_OPT_SYNTAX_INTEL);
    
    cs_insn* insn;
    size_t count = cs_disasm(handle, code, size, 0x1000, 0, &insn);
    
    std::vector<DisassemblyResult> results;
    for (size_t i = 0; i < count; i++) {
        results.push_back({
            "0x" + std::to_string(insn[i].address),
            "",  // bytes
            insn[i].mnemonic,
            insn[i].op_str,
            ""
        });
    }
    
    cs_free(insn, count);
    cs_close(&handle);
    return results;
}
