bool Load800BParallel(const std::vector<std::string>& shard_paths, 
                      const std::string& output_path) {
    const size_t NUM_THREADS = 5;
    std::vector<std::thread> threads;
    std::atomic<size_t> bytes_loaded{0};
    
    // Create output file with sparse allocation
    HANDLE hOut = CreateFileA(output_path.c_str(), GENERIC_WRITE, 0, nullptr, 
                              CREATE_ALWAYS, FILE_ATTRIBUTE_NORMAL, nullptr);
    LARGE_INTEGER size;
    size.QuadPart = 800ULL * 1024 * 1024 * 1024; // 800GB
    SetFilePointerEx(hOut, size, nullptr, FILE_BEGIN);
    SetEndOfFile(hOut);
    CloseHandle(hOut);
    
    // Memory-map output
    hOut = CreateFileA(output_path.c_str(), GENERIC_READ | GENERIC_WRITE, 
                       FILE_SHARE_READ, nullptr, OPEN_EXISTING, 
                       FILE_ATTRIBUTE_NORMAL | FILE_FLAG_OVERLAPPED, nullptr);
    HANDLE hMap = CreateFileMapping(hOut, nullptr, PAGE_READWRITE, 
                                    size.HighPart, size.LowPart, nullptr);
    
    // Parallel load shards
    for (size_t i = 0; i < shard_paths.size(); i++) {
        threads.emplace_back([&, i]() {
            // Map shard to memory
            HANDLE hIn = CreateFileA(shard_paths[i].c_str(), GENERIC_READ, 
                                    FILE_SHARE_READ, nullptr, OPEN_EXISTING, 
                                    FILE_FLAG_OVERLAPPED, nullptr);
            HANDLE hInMap = CreateFileMapping(hIn, nullptr, PAGE_READONLY, 0, 0, nullptr);
            LPVOID pIn = MapViewOfFile(hInMap, FILE_MAP_READ, 0, 0, 0);
            
            // Copy to output at correct offset
            size_t offset = i * (100ULL * 1024 * 1024 * 1024); // 100GB per shard
            LPVOID pOut = MapViewOfFile(hMap, FILE_MAP_WRITE, 
                                        offset >> 32, offset & 0xFFFFFFFF, 0);
            
            memcpy(pOut, pIn, 100ULL * 1024 * 1024 * 1024);
            bytes_loaded += 100ULL * 1024 * 1024 * 1024;
            
            UnmapViewOfFile(pIn);
            UnmapViewOfFile(pOut);
            CloseHandle(hInMap);
            CloseHandle(hIn);
        });
    }
    
    for (auto& t : threads) t.join();
    CloseHandle(hMap);
    CloseHandle(hOut);
    
    return bytes_loaded == 800ULL * 1024 * 1024 * 1024;
}
