    GGML_TYPE_Q4_0 = 2,
    GGML_TYPE_Q4_1 = 3,
    GGML_TYPE_Q5_0 = 6,
    GGML_TYPE_Q5_1 = 7,
    GGML_TYPE_Q8_0 = 8,
};

// Q4_0 block: 32 weights, 1 scale (f16), 16 bytes total
struct BlockQ4_0 {
    uint16_t d;     // scale
    uint8_t qs[16]; // 4-bit weights (32 values packed)
};

// Real AVX-512 matrix multiplication
void matmul_q4_0_avx512(const float* x, const BlockQ4_0* w, float* y, 
                        int n, int m, int k) {
    // n = input rows, m = output cols, k = inner dim
    // x: [n, k], w: [m, k/32] blocks, y: [n, m]
    
    const int blocks_per_row = k / 32;
    
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            __m512 sum_vec = _mm512_setzero_ps();
            
            for (int b = 0; b < blocks_per_row; b++) {
                const BlockQ4_0* block = &w[j * blocks_per_row + b];
                
                // Dequantize scale
                float d = *reinterpret_cast<const float*>(&block->d);
                
                // Load 32 input values
                __m512 x_vec = _mm512_loadu_ps(&x[i * k + b * 32]);
                
                // Dequantize weights: 4-bit packed -> 32 floats
                // Unpack 16 bytes into 32 nibbles
                __m256i qs = _mm256_loadu_si256((__m256i*)block->qs);
                
                // Low nibbles: (qs & 0x0F) - 8
                __m256i low_mask = _mm256_set1_epi8(0x0F);
                __m256i low = _mm256_and_si256(qs, low_mask);
                low = _mm256_sub_epi8(low, _mm256_set1_epi8(8));
                
                // High nibbles: (qs >> 4) - 8  
                __m256i high = _mm256_srli_epi16(qs, 4);
                high = _mm256_and_si256(high, low_mask);
                high = _mm256_sub_epi8(high, _mm256_set1_epi8(8));
                
                // Convert to float and accumulate
                __m256i lo16 = _mm256_cvtepi8_epi16(_mm256_castsi256_si128(low));
                __m256i hi16 = _mm256_cvtepi8_epi16(_mm256_extracti128_si256(low, 1));
                
                __m512 w_lo = _mm512_cvtepi32_ps(_mm512_cvtepi16_epi32(lo16));
                __m512 w_hi = _mm512_cvtepi32_ps(_mm512_cvtepi16_epi32(hi16));
                
                // Apply scale and accumulate
                __m512 d_vec = _mm512_set1_ps(d);
                sum_vec = _mm512_fmadd_ps(x_vec, _mm512_mul_ps(w_lo, d_vec), sum_vec);
                
                // Second half
                x_vec = _mm512_loadu_ps(&x[i * k + b * 32 + 16]);
                lo16 = _mm256_cvtepi8_epi16(_mm256_castsi256_si128(high));
                hi16 = _mm256_cvtepi8_epi16(_mm256_extracti128_si256(high, 1));
                w_lo = _mm512_cvtepi32_ps(_mm512_cvtepi16_epi32(lo16));
                w_hi = _mm512_cvtepi32_ps(_mm512_cvtepi16_epi32(hi16));
                sum_vec = _mm512_fmadd_ps(x_vec, _mm512_mul_ps(w_lo, d_vec), sum_vec);
            }
            
            y[i * m + j] = _mm512_reduce_add_ps(sum_vec);
        }
    }
}

// Real RoPE (Rotary Position Embedding)
void rope_avx512(float* q, float* k, int head_dim, int pos, float theta = 10000.0f) {
    for (int i = 0; i < head_dim; i += 2) {
        int idx = i / 2;
        float freq = 1.0f / powf(theta, (2.0f * idx) / head_dim);
        float val = pos * freq;
        float fcr = cosf(val);
        float fci = sinf(val);
        
        float q0 = q[i], q1 = q[i+1];
        float k0 = k[i], k1 = k[i+1];
        
        q[i]   = q0 * fcr - q1 * fci;
        q[i+1] = q0 * fci + q1 * fcr;
        k[i]   = k0 * fcr - k1 * fci;
        k[i+1] = k0 * fci + k1 * fcr;
    }
}

// Real Softmax
void softmax(float* x, int size) {
    float max_val = x[0];
    for (int i = 1; i < size; i++) max_val = std::max(max_val, x[i]);
    
    float sum = 0.0f;
    for (int i = 0; i < size; i++) {
        x[i] = expf(x[i] - max_val);
        sum += x[i];
    }
    
    for (int i = 0; i < size; i++) x[i] /= sum;
}

// Real Multi-Head Attention
void attention_forward(float* out, float* q, float* k, float* v,
                       int n_heads, int head_dim, int seq_len) {
    int dim = n_heads * head_dim;
    
    #pragma omp parallel for
    for (int h = 0; h < n_heads; h++) {
        float* q_h = q + h * head_dim;
        float* k_h = k + h * head_dim;
        float* v_h = v + h * head_dim;
        float* out_h = out + h * head_dim;
        
        // Attention scores: q @ k^T
        float scores[4096]; // Max seq len
        
        for (int t = 0; t < seq_len; t++) {
            float* k_t = k_h + t * dim; // Key at position t
            float score = 0.0f;
            for (int i = 0; i < head_dim; i++) {
                score += q_h[i] * k_t[i];
            }
            scores[t] = score / sqrtf(head_dim);
        }
        
        // Causal mask (only attend to previous tokens)
        for (int t = seq_len; t < 4096; t++) scores[t] = -1e9f;
        
        softmax(scores, seq_len);
        
        // Weighted sum of values
        for (int i = 0; i < head_dim; i++) out_h[i] = 0.0f;
        for (int t = 0; t < seq_len; t++) {
            float* v_t = v_h + t * dim;
            for (int i = 0; i < head_dim; i++) {
                out_h[i] += scores[t] * v_t[i];
            }
        }
    }
}

// Real Feed-Forward Network (SwiGLU)
void ffn_forward(float* out, float* x, float* w1, float* w2, float* w3,
                 int dim, int hidden_dim) {
    float tmp1[16384], tmp2[16384], tmp3[16384];
    
    // w1 @ x
    for (int i = 0; i < hidden_dim; i++) {
        tmp1[i] = 0;
        for (int j = 0; j < dim; j++) tmp1[i] += w1[i * dim + j] * x[j];
    }
    
    // w3 @ x  
    for (int i = 0; i < hidden_dim; i++) {
        tmp3[i] = 0;
        for (int j = 0; j < dim; j++) tmp3[i] += w3[i * dim + j] * x[j];
    }
    
    // SwiGLU: silu(w1*x) * (w3*x)
    for (int i = 0; i < hidden_dim; i++) {
        float silu = tmp1[i] * (1.0f / (1.0f + expf(-tmp1[i]))); // x * sigmoid(x)
        tmp2[i] = silu * tmp3[i];
    }
    
    // w2 @ result
    for (int i = 0; i < dim; i++) {
        out[i] = 0;
        for (int j = 0; j < hidden_dim; j++) out[i] += w2[i * hidden_dim + j] * tmp2[j];
    }
