// RMS Normalization
void rmsnorm(float* out, float* x, float* weight, int size, float eps = 1e-6f) {
    float ss = 0.0f;
    for (int i = 0; i < size; i++) ss += x[i] * x[i];
    ss /= size;
    ss += eps;
    ss = 1.0f / sqrtf(ss);
    
    for (int i = 0; i < size; i++) out[i] = weight[i] * (ss * x[i]);
}

