    // Self-attention
    rmsnorm(tmp, x, attn_norm, dim);
    
    // QKV projections
    for (int i = 0; i < dim; i++) {
        q[i] = k[i] = v[i] = 0;
        for (int j = 0; j < dim; j++) {
            q[i] += wq[i * dim + j] * tmp[j];
            k[i] += wk[i * dim + j] * tmp[j];
            v[i] += wv[i * dim + j] * tmp[j];
        }
    }
    
    // Apply RoPE
    for (int h = 0; h < n_heads; h++) {
        rope_avx512(q + h * head_dim, k + h * head_dim, head_dim, pos);
    }
    
    // Multi-head attention
    attention_forward(attn_out, q, k, v, n_heads, head_dim, seq_len);
    
    // Output projection + residual
    for (int i = 0; i < dim; i++) {
        float out = 0;
        for (int j = 0; j < dim; j++) out += wo[i * dim + j] * attn_out[j];
        x[i] += out;
    }
    
    // FFN
    rmsnorm(tmp, x, ffn_norm, dim);
    ffn_forward(attn_out, tmp, w1, w2, w3, dim, hidden_dim);
    
    // Residual
    for (int i = 0; i < dim; i++) x[i] += attn_out[i];
}
