// gguf_loader.cpp - Real implementation
#include <windows.h>
#include <fstream>
#include <cstring>

class GGUFLoader {
    HANDLE hFile = INVALID_HANDLE_VALUE;
    HANDLE hMap = NULL;
    void* pMap = nullptr;
    size_t fileSize = 0;
    
    GGUFHeader header;
    std::vector<TensorInfo> tensors;
    std::unordered_map<std::string, std::string> metadata;
    
public:
    bool load(const std::string& path) {
        // Memory map the file for zero-copy access
        hFile = CreateFileA(path.c_str(), GENERIC_READ, FILE_SHARE_READ, 
                           NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
        if (hFile == INVALID_HANDLE_VALUE) return false;
        
        LARGE_INTEGER size;
        GetFileSizeEx(hFile, &size);
        fileSize = size.QuadPart;
        
        hMap = CreateFileMapping(hFile, NULL, PAGE_READONLY, 0, 0, NULL);
        if (!hMap) return false;
        
        pMap = MapViewOfFile(hMap, FILE_MAP_READ, 0, 0, 0);
        if (!pMap) return false;
        
        // Parse header
        uint8_t* ptr = (uint8_t*)pMap;
        memcpy(&header, ptr, sizeof(GGUFHeader));
        ptr += sizeof(GGUFHeader);
        
        // Verify magic (GGUF = 0x46554747 little endian)
        if (header.magic != 0x46554747) {
            unmap();
            return false;
        }
        
        // Parse metadata KV
        for (uint64_t i = 0; i < header.metadata_kv_count; i++) {
            // Read key length and key
            uint64_t key_len = read_u64(ptr);
            std::string key((char*)ptr, key_len);
            ptr += key_len;
            
            // Read value type and value
            uint32_t type = read_u32(ptr);
            std::string value = read_value(ptr, type);
            
            metadata[key] = value;
        }
        
        // Parse tensor info
        for (uint64_t i = 0; i < header.tensor_count; i++) {
            TensorInfo info;
            
            uint64_t name_len = read_u64(ptr);
            info.name = std::string((char*)ptr, name_len);
            ptr += name_len;
            
            info.n_dims = read_u32(ptr);
            for (uint32_t d = 0; d < info.n_dims; d++) {
                info.dims[d] = read_u64(ptr);
            }
            
            info.type = read_u32(ptr);
            info.offset = read_u64(ptr);
            
            tensors.push_back(info);
        }
        
        // Tensor data starts at aligned offset
        tensor_data_offset = ((ptr - (uint8_t*)pMap) + 31) & ~31;
        
        return true;
    }
    
    // Get pointer to tensor data (zero-copy)
    void* get_tensor(const std::string& name, size_t& size, GGMLType& type) {
        for (const auto& t : tensors) {
            if (t.name == name) {
                size = calculate_size(t);
                type = (GGMLType)t.type;
                return (uint8_t*)pMap + tensor_data_offset + t.offset;
            }
        }
        return nullptr;
    }
    
    // Dequantize Q4_0 to F32 in-place or to buffer
    void dequantize_q4_0(void* dst, const void* src, int n, int k) {
        const BlockQ4_0* blocks = (const BlockQ4_0*)src;
        float* out = (float*)dst;
        
        int blocks_per_row = k / 32;
        
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < k; j++) {
                int block_idx = j / 32;
                int idx_in_block = j % 32;
                
                const BlockQ4_0& block = blocks[i * blocks_per_row + block_idx];
                float d = *(float*)&block.d;
                
                uint8_t q = block.qs[idx_in_block / 2];
                int8_t val = (idx_in_block % 2 == 0) ? (q & 0x0F) : (q >> 4);
                val -= 8; // offset
                
                out[i * k + j] = val * d;
            }
        }
    }
    
    void unmap() {
        if (pMap) UnmapViewOfFile(pMap);
        if (hMap) CloseHandle(hMap);
        if (hFile != INVALID_HANDLE_VALUE) CloseHandle(hFile);
    }
    
private:
    size_t tensor_data_offset = 0;
    
    uint64_t read_u64(uint8_t*& ptr) {
        uint64_t val = *(uint64_t*)ptr;
        ptr += 8;
        return val;
    }
    
    uint32_t read_u32(uint8_t*& ptr) {
        uint32_t val = *(uint32_t*)ptr;
        ptr += 4;
        return val;
    }
    
    size_t calculate_size(const TensorInfo& t) {
        size_t n_elements = 1;
        for (uint32_t i = 0; i < t.n_dims; i++) n_elements *= t.dims[i];
        
        switch (t.type) {
            case GGML_TYPE_F32: return n_elements * 4;
            case GGML_TYPE_F16: return n_elements * 2;
            case GGML_TYPE_Q4_0: return (n_elements / 32) * sizeof(BlockQ4_0);
            case GGML_TYPE_Q8_0: return (n_elements / 32) * (sizeof(float) + 32);
            default: return 0;
        }
    }
};
