// sampler.cpp - Real sampling algorithms
#include <random>
#include <algorithm>
#include <numeric>

struct Sampler {
    float temperature = 0.8f;
    int top_k = 40;
    float top_p = 0.9f;
    
    std::mt19937 rng;
    
    Sampler() : rng(std::random_device{}()) {}
    
    int sample(float* logits, int n_vocab) {
        // Apply temperature
        if (temperature != 1.0f) {
            for (int i = 0; i < n_vocab; i++) {
                logits[i] /= temperature;
            }
        }
        
        // Softmax
        float max_logit = *std::max_element(logits, logits + n_vocab);
        float sum = 0.0f;
        for (int i = 0; i < n_vocab; i++) {
            logits[i] = expf(logits[i] - max_logit);
            sum += logits[i];
        }
        for (int i = 0; i < n_vocab; i++) logits[i] /= sum;
        
        // Top-K filtering
        if (top_k > 0 && top_k < n_vocab) {
            // Partial sort to find k-th largest
            std::nth_element(logits, logits + top_k, logits + n_vocab, std::greater<float>());
            float kth = logits[top_k];
            for (int i = 0; i < n_vocab; i++) {
                if (logits[i] < kth) logits[i] = 0;
            }
            // Renormalize
            sum = std::accumulate(logits, logits + n_vocab, 0.0f);
            for (int i = 0; i < n_vocab; i++) logits[i] /= sum;
        }
        
        // Top-P (nucleus) filtering
        if (top_p < 1.0f) {
            // Sort probabilities descending
            std::vector<std::pair<float, int>> probs;
            for (int i = 0; i < n_vocab; i++) probs.push_back({logits[i], i});
            std::sort(probs.begin(), probs.end(), std::greater<>());
            
            // Cumulative sum until > top_p
            float cumsum = 0.0f;
            for (auto& [p, idx] : probs) {
                cumsum += p;
                if (cumsum > top_p) {
                    // Zero out remaining
                    for (auto it = &p + 1; it != probs.end(); ++it) {
                        logits[it->second] = 0;
                    }
                    break;
                }
            }
            // Renormalize
            sum = std::accumulate(logits, logits + n_vocab, 0.0f);
            for (int i = 0; i < n_vocab; i++) logits[i] /= sum;
        }
        
        // Sample from distribution
        std::discrete_distribution<int> dist(logits, logits + n_vocab);
        return dist(rng);
    }
};
